const item = $input.first().json;

let error_type = item.error_type;
let error_message = item.error_message;
let workflow_id = item.workflow_id;
let workflow_name = item.workflow_name;
let error_code = item.error_code;

if (item.execution?.error) {
  error_type = error_type || 'System Error';
  error_message =
    item.execution.error.message ||
    item.execution.error.description ||
    String(item.execution.error);
  workflow_id = item.workflow?.id || workflow_id;
  workflow_name = item.workflow?.name || workflow_name;
  error_code = error_code || 'SE?';
}

if (!error_type) {
  error_type = 'System Error';
}

if (!error_message) {
  error_message = 'Unknown error (no message provided)';
}

if (!error_code) {
  error_code = error_type === 'Business Error' ? 'BE?' : 'SE?';
}

return [
  {
    json: {
      success: false,
      error_type,
      error_message,
      error_code,
      workflow_id: workflow_id || $workflow.id,
      workflow_name: workflow_name || 'BreaksRecovery',
      timestamp: new Date().toISOString(),
    },
  },
];

const err = $('Normalize Error').first().json;
const config = $input.first().json;

function maskPii(text) {
  let s = String(text ?? '');
  s = s.replace(/[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}/g, '***@***');
  s = s.replace(/(login|агент|agent)[\s:]+[\w.-]+/gi, '$1: ***');
  return s;
}

const isBusiness = err.error_type === 'Business Error';
const channel = isBusiness
  ? config.MMCBotAlertChannel
  : config.MMCBotProdNotificationsChannel;

const robotName = config.robotName || 'BreaksRecovery';
const wf = err.workflow_name || 'BreaksRecovery';
const ts = err.timestamp;
const statusLabel = isBusiness ? 'Business Error' : 'Error';
const safeMessage = maskPii(err.error_message);

const notify_message = [
  `Название робота: ${robotName}`,
  `Процесс: ${wf}`,
  `Время запуска: ${ts}`,
  `Статус: ${statusLabel}`,
  `Тип: ${err.error_code}`,
  `Описание: ${safeMessage}`,
].join('; ');

return [
  {
    json: {
      ...err,
      error_message_safe: safeMessage,
      robotName,
      environment: config.environment,
      DBSchemaName: config.DBSchemaName,
      DBTableNameRecoveryTransactions: config.DBTableNameRecoveryTransactions,
      MattermostAPIURL: config.MattermostAPIURL,
      Mattermost1CChannelBaseURL: config.Mattermost1CChannelBaseURL,
      notify_channel: channel,
      notify_message,
      processing_status: 'failed',
      needs_email_fallback: !isBusiness,
    },
  },
];

const err = $('Enrich With Config').first().json;

return [
  {
    json: {
      success: false,
      error_type: err.error_type,
      error_message: err.error_message,
      error_code: err.error_code,
      workflow_name: err.workflow_name,
      handler_completed: true,
    },
  },
];
